import { Component, Prop, h, Event, EventEmitter, Element } from '@stencil/core';

export type CardLinkType = 'button' | 'caret' | 'radio' | 'checkbox' | 'ellipses' | 'slot';

/**
 * Card link component: renders a button, caret, ellipses, radio, checkbox, or custom slot content.
 */
@Component({
  tag: 'wdpr-card-link',
  shadow: true,
  styles: `
    :host {
      display: flex;
      align-items: center;
    }
  `,
})
export class WdprCardLink {
  @Element() el: HTMLElement;
  @Prop() type: CardLinkType = 'button';
  @Prop() disabled?: boolean = false;
  @Prop({ mutable: true, reflect: true }) checked?: boolean = false;
  @Prop() name?: string;
  @Prop() value?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;
  @Event() clicked: EventEmitter<void>;

  private _handleClick = (e: Event) => {
    if (this.disabled) {
      e.preventDefault();
      e.stopPropagation();

      return;
    }

    if (this.type === 'button' || this.type === 'caret' || this.type === 'ellipses' || this.type === 'radio' || this.type === 'checkbox' || this.type === 'slot') {
      e.preventDefault();
      e.stopPropagation();
      this.clicked.emit();
    }
  };

  render() {
    if (this.type === 'button') {
      return (
        <wdpr-button variant="secondary" a11yLabel="Card Button" size="small" disabled={this.disabled} onClick={this._handleClick}>
          <slot></slot>
        </wdpr-button>
      );
    }

    if (this.type === 'caret') {
      return (
        <wdpr-icon-button
          iconName="next-caret-2.0"
          size="small"
          disabled={this.disabled}
          a11yLabel="Card Caret Link"
          onClick={this._handleClick}
          onClicked={e => e.stopPropagation()}
          aria-disabled={this.disabled ? 'true' : 'false'}
        ></wdpr-icon-button>
      );
    }

    if (this.type === 'ellipses') {
      return (
        <wdpr-icon-button
          iconName="more"
          size="small"
          disabled={this.disabled}
          a11yLabel={this.a11yLabel || 'More options'}
          onClick={this._handleClick}
          aria-disabled={this.disabled ? 'true' : 'false'}
        ></wdpr-icon-button>
      );
    }

    if (this.type === 'radio') {
      return <wdpr-radio-button onClick={this._handleClick} name="option" value="option1" customAriaLabel={this.a11yLabel} disabled={this.disabled}></wdpr-radio-button>;
    }

    if (this.type === 'checkbox') {
      return <wdpr-checkbox onClick={this._handleClick} checked={this.checked} labelPosition="none" customAriaLabel={this.a11yLabel} disabled={this.disabled}></wdpr-checkbox>;
    }

    if (this.type === 'slot') {
      return (
        <div onClick={this._handleClick}>
          <slot></slot>
        </div>
      );
    }
  }
}
