import { Component, h, Prop, Host, Element, Event, EventEmitter } from '@stencil/core';
import { MediaPosition } from '../../components';
import { propagateToSlot } from '../../utils/utils';
import { HeadingLevel } from '../../models/card.model';

export type ActionPosition = 'leading' | 'trailing' | 'none';

/**
 * @deprecated Use `wdpr-card-micro` starting in release 3.0.4. `wdpr-guest-card` will be removed in a future major release.
 */
@Component({
  tag: 'wdpr-guest-card',
  shadow: true,
  styles: `
    :host { display: block; }
    :host([full-width]) { width: 100%; }
    :host([disabled]) {
      pointer-events: none;
      opacity: 0.5;
    }
  `,
})
export class WdprGuestCard {
  @Element() el: HTMLElement;

  @Prop() isOnSurface: boolean = false;
  @Prop() actionPosition: ActionPosition = 'none';
  @Prop() mediaPosition: MediaPosition = 'leading';
  @Prop({ reflect: true, attribute: 'full-width' }) fullWidth: boolean = false;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop() headingLevel: HeadingLevel = 'h3';
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;
  @Prop() selected: boolean = false;

  @Event() wdprSelectedChange: EventEmitter<{ selected: boolean }>;

  componentWillLoad() {
    console.warn('The wdpr-guest-card component is deprecated and will be removed in a future major release');
  }

  componentDidLoad() {
    const slot = this.el.shadowRoot?.querySelector('slot[name="content"]') as HTMLSlotElement;
    propagateToSlot(slot, 'headingLevel', this.headingLevel, 'wdpr-card-micro-content', 'heading-level');
  }

  private _handleSelectedChange = (event: CustomEvent<{ selected: boolean }>) => {
    event.stopPropagation();
    this.wdprSelectedChange.emit(event.detail);
  };

  render() {
    return (
      <Host>
        <wdpr-card-micro
          mediaPosition={this.mediaPosition}
          fullWidth={this.fullWidth}
          actionPosition={this.actionPosition}
          isOnSurface={this.isOnSurface}
          disabled={this.disabled}
          a11yLabel={this.a11yLabel}
          selected={this.selected}
          onWdprSelectedChange={this._handleSelectedChange}
        >
          <slot name="media" slot="media" />
          <slot name="content" slot="content" />
          <slot name="link" slot="link" />
          <slot name="footer" slot="footer" />
        </wdpr-card-micro>
      </Host>
    );
  }
}
